 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Label } from '@patternfly/react-core';
 8	import { getPlanPreserveClusterCpuModel } from '@utils/crds/plans/selectors';
 9	
10	import type { EditableDetailsItemProps } from '../../../utils/types';
11	
12	import EditPlanPreserveClusterCpuModel from './EditPlanPreserveClusterCpuModel';
13	
14	const PreserveClusterCpuModelDetailsItem: FC<EditableDetailsItemProps> = ({
15	  canPatch,
16	  plan,
17	  shouldRender,
18	}) => {
19	  const { t } = useForkliftTranslation();
20	  const { showModal } = useModal();
21	
22	  if (!shouldRender) return null;
23	
24	  const preserveClusterCpuModel = getPlanPreserveClusterCpuModel(plan);
25	
26	  return (
27	    <DetailsItem
28	      title={t('Preserve CPU model')}
29	      content={
30	        <Label isCompact color="grey">
31	          {preserveClusterCpuModel ? t('Preserve CPU model') : t('Use system default')}
32	        </Label>
33	      }
34	      helpContent={t(`Preserve the CPU model and flags the VM runs with in its oVirt cluster.`)}
35	      crumbs={['spec', 'preserveClusterCpuModel']}
36	      onEdit={() => {
37	        showModal(<EditPlanPreserveClusterCpuModel resource={plan} />);
38	      }}
39	      canEdit={canPatch && isPlanEditable(plan)}
40	    />
41	  );
42	};
43	
44	export default PreserveClusterCpuModelDetailsItem;

